from langchain_core.prompts import ChatPromptTemplate
import re

# Validate that all required variables are present before invoking the chain
def validate_template_inputs(template: ChatPromptTemplate, inputs: dict) -> list[str]:
    missing = []
    for var in template.input_variables:
        if var not in inputs:
            missing.append(var)
    return missing

template = ChatPromptTemplate.from_template(
    "Summarise the following {document_type} in {max_words} words:\n\n{document}"
)

inputs = {"document_type": "contract", "document": "This agreement..."}
# max_words is missing
missing = validate_template_inputs(template, inputs)
if missing:
    raise ValueError(f"Missing template variables: {missing}")
# -> ValueError: Missing template variables: ['max_words']

# Partial templates: pre-fill static variables and leave dynamic ones open
partial_template = template.partial(max_words="200")
# Now only document_type and document are required
result = partial_template.invoke({
    "document_type": "contract",
    "document": "This agreement between Acme and Beta...",
})
